// Game constants
export const CANVAS_WIDTH = 600;
export const CANVAS_HEIGHT = 400;
export const CARD_WIDTH = 80;
export const CARD_HEIGHT = 120;
export const MAX_ENERGY = 3;
export const STARTING_HAND_SIZE = 5;
export const MAX_HAND_SIZE = 10;
export const PLAYER_MAX_HEALTH = 80;

// Game state object
export const gameState = {
  gamePhase: "START",  // "START", "PLAYING", "PAUSED", "GAME_OVER_WIN", "GAME_OVER_LOSE"
  controlMode: "HUMAN", // "HUMAN", "TEST_1", "TEST_2", "TEST_3", etc.
  player: null,
  enemies: [],
  currentEnemy: null,
  currentEnemyIndex: 0,
  totalEnemies: 5,
  deck: [],
  hand: [],
  drawPile: [],
  discardPile: [],
  energy: MAX_ENERGY,
  turn: "PLAYER", // "PLAYER" or "ENEMY"
  selectedCardIndex: 0,
  viewingPile: null, // "DRAW" or "DISCARD" or null
  battleState: "SELECT_CARD", // "SELECT_CARD", "SELECT_TARGET", "ENEMY_TURN", "REWARD"
  availableRewards: [],
  selectedRewardIndex: 0,
  battleCount: 0,
  keyStates: {
    up: false,
    down: false,
    left: false,
    right: false,
    space: false,
    shift: false,
    z: false
  }
};

// Card types
export const CARD_TYPES = {
  ATTACK: {
    name: "Attack",
    color: [220, 60, 60]
  },
  SKILL: {
    name: "Skill",
    color: [60, 180, 220]
  },
