    name: "Power",
    color: [180, 100, 220]
  }
};

// Card templates
export const CARD_TEMPLATES = [
  {
    id: "strike",
    name: "Strike",
    type: CARD_TYPES.ATTACK,
    energy: 1,
    description: "Deal 6 damage",
    effect: (target) => {
      target.health -= 6;
    }
  },
  {
    id: "defend",
    name: "Defend",
    type: CARD_TYPES.SKILL,
    energy: 1,
    description: "Gain 5 block",
    effect: (player) => {
      player.block += 5;
    }
  },
  {
    id: "bash",
    name: "Bash",
    type: CARD_TYPES.ATTACK,
    energy: 2,
    description: "Deal 8 damage and apply 2 vulnerable",
    effect: (target) => {
      target.health -= 8;
      target.vulnerable = (target.vulnerable || 0) + 2;
    }
  },
  {
    id: "cleave",
    name: "Cleave",
    type: CARD_TYPES.ATTACK,
    energy: 1,
    description: "Deal 8 damage",
    effect: (target) => {
      target.health -= 8;
    }
  },
  {
    id: "iron_wave",
    name: "Iron Wave",
    type: CARD_TYPES.ATTACK,
    energy: 1,
    description: "Deal 5 damage and gain 5 block",
    effect: (target, player) => {
      target.health -= 5;
      player.block += 5;
    }
  },
  {
    id: "shrug_it_off",
    name: "Shrug It Off",
    type: CARD_TYPES.SKILL,
    energy: 1,
