    }
  },
  {
    id: "true_grit",
    name: "True Grit",
    type: CARD_TYPES.SKILL,
    energy: 1,
    description: "Gain 7 block",
    effect: (player) => {
      player.block += 7;
    }
  },
  {
    id: "battle_trance",
    name: "Battle Trance",
    type: CARD_TYPES.SKILL,
    energy: 0,
