// Enemy templates
export const ENEMY_TEMPLATES = [
  {
    id: "slime",
    name: "Slime",
    health: 14,
    maxHealth: 14,
    intentions: ["ATTACK", "DEFEND", "ATTACK"],
    attackDamage: 7,
    blockAmount: 5,
    color: [120, 200, 100]
  },
  {
    id: "cultist",
    name: "Cultist",
    health: 20,
    maxHealth: 20,
    intentions: ["BUFF", "ATTACK", "ATTACK"],
    attackDamage: 6,
    blockAmount: 0,
    color: [150, 50, 200]
  },
  {
    id: "jaw_worm",
    name: "Jaw Worm",
    health: 40,
    maxHealth: 40,
    intentions: ["ATTACK", "DEFEND", "ATTACK", "BUFF"],
    attackDamage: 11,
    blockAmount: 6,
    color: [220, 120, 50]
  },
  {
    id: "thief",
    name: "Thief",
    health: 28,
    maxHealth: 28,
    intentions: ["ATTACK", "DEBUFF", "ATTACK"],
    attackDamage: 9,
    blockAmount: 0,
    color: [70, 130, 180]
  },
  {
    id: "boss",
    name: "The Guardian",
    health: 60,
    maxHealth: 60,
    intentions: ["DEFEND", "ATTACK", "ATTACK", "DEFEND", "HEAVY_ATTACK"],
    attackDamage: 8,
    heavyAttackDamage: 16,
    blockAmount: 9,
    color: [200, 60, 60]
  }
];

// Helper function to draw cards
export function drawCard(gameState, count = 1) {
  for (let i = 0; i < count; i++) {
    if (gameState.drawPile.length === 0) {
      // Shuffle discard pile into draw pile
      gameState.drawPile = [...gameState.discardPile];
      gameState.discardPile = [];
      shuffleArray(gameState.drawPile);
    }

    if (gameState.drawPile.length > 0 && gameState.hand.length < MAX_HAND_SIZE) {
      const card = gameState.drawPile.pop();
      gameState.hand.push(card);
    }
  }
}

// Shuffle array helper
export function shuffleArray(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
}

// Function to get game state
export function getGameState() {
  return gameState;
}

// Expose the getGameState function globally
window.getGameState = getGameState;
